import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import ReactCrop from 'react-image-crop'; // Import the cropping library
import 'react-image-crop/dist/ReactCrop.css'; // Don't forget the library's styles!
import './Css/Admin.css'; // We will create this next

// Common aspect ratio that matches the Landing page's 3D carousel cards
const ASPECT_RATIO = 320 / 180;

const AdminDashboard = () => {
  const navigate = useNavigate();
  const [games, setGames] = useState([]);

  // MAIN STATE: Controls the entire form (shared by Add and Edit)
  const [gameFormData, setGameFormData] = useState({
    id: null,
    title: '',
    genre: '',
    image_url: '',
    crop_data: null // This is where we will store the coordinate string
  });

  // CROPPING STATE (for the library)
  // We explicitly set a starting area for the user
  const [crop, setCrop] = useState({ unit: '%', width: 80, height: 80, x: 10, y: 10, aspect: ASPECT_RATIO });
  const [completedCrop, setCompletedCrop] = useState(null);

  const fetchGames = async () => {
    const response = await fetch('http://localhost:8000/api/top-games');
    const data = await response.json();
    if (data.status === 'success') setGames(data.games);
  };

  useEffect(() => {
    fetchGames();
  }, []);

  const handleLogout = () => navigate('/');

  // Reset all states to "Add New Game" mode
  const resetFormState = () => {
    setGameFormData({ id: null, title: '', genre: '', image_url: '', crop_data: null });
    setCrop({ unit: '%', width: 80, height: 80, x: 10, y: 10, aspect: ASPECT_RATIO });
    setCompletedCrop(null);
  };

  // Pre-fills the form and activates edit mode
  const handleEditClick = (game) => {
    console.log("Edit clicked for game:", game);
    setGameFormData({
      id: game.id,
      title: game.title,
      genre: game.genre,
      image_url: game.image, // Use game.image, which is the URL from the DB
      crop_data: game.crop_data
    });

    // If we have previous crop data, we pre-fill the cropping tool
    if (game.crop_data) {
      try {
        const parsedCrop = JSON.parse(game.crop_data);
        setCrop({ unit: '%', width: parsedCrop.width, height: parsedCrop.height, x: parsedCrop.x, y: parsedCrop.y, aspect: ASPECT_RATIO });
      } catch (e) {
        console.error("error parsing crop data on edit start", e);
      }
    } else {
        resetFormState(); // reset if there is no previous data
        // Resetting just crop is sufficient, as gameFormData already gets values above
        setCrop({ unit: '%', width: 80, height: 80, x: 10, y: 10, aspect: ASPECT_RATIO });
        setCompletedCrop(null);
    }
  };

  // Shared form handler that handles both "Add" and "Save Changes"
  const handleSaveGame = async (e) => {
    e.preventDefault();

    // THE PRO LOGIC: Prepare the Final Crop Coordinate
    // completedCrop is where we get the percentage values of the selected area
    let finalCropDataString = null;
    if (completedCrop && completedCrop.width > 0 && completedCrop.height > 0) {
      // The frontend logic doesn't need to know *what* to crop. It only needs to know
      // which part of the image becomes the *center* of the card.
      // So, during save, we calculate and store the precise (x%, y%) center point.
      const centerX = completedCrop.x + completedCrop.width / 2;
      const centerY = completedCrop.y + completedCrop.height / 2;
      finalCropDataString = JSON.stringify({ x: centerX, y: centerY });
    }

    // CREATE THE PAYLOAD
    const payload = {
      title: gameFormData.title,
      genre: gameFormData.genre,
      image_url: gameFormData.image_url,
      crop_data: finalCropDataString // This is the coordinate string Python will save
    };

    // CHOOSE THE API ENDPOINT (Add/Post or Edit/Put)
    const isEditMode = gameFormData.id !== null;
    const url = isEditMode 
      ? `http://localhost:8000/api/games/${gameFormData.id}` 
      : 'http://localhost:8000/api/games';
    const method = isEditMode ? 'PUT' : 'POST';

    const response = await fetch(url, {
      method: method,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });
    const result = await response.json();

    if (result.status === 'success') {
      alert(`Game ${isEditMode ? 'Updated' : 'Added'} Successfully!`);
      resetFormState(); // Clear and reset to "Add" mode
      fetchGames(); // Refresh the list from the database
    }
  };

  const handleDelete = async (id) => {
    if(window.confirm("Are you sure you want to delete this game?")) {
      const response = await fetch(`http://localhost:8000/api/games/${id}`, { method: 'DELETE' });
      const result = await response.json();
      if (result.status === 'success') fetchGames(); // Refresh the list
    }
  };

  const isEditMode = gameFormData.id !== null;

  return (
    <div className="admin-container">
      <header className="admin-header">
        <div className="logo">GAMING<span>HUB</span> <strong>// ADMIN PANEL</strong></div>
        <button className="logout-btn" onClick={handleLogout}>Logout</button>
      </header>

      <div className="admin-content">
        {/* SHARED FORM (Dynamically changes between Add and Edit) */}
        <section className="admin-card form-section">
          <h2>{isEditMode ? `Editing: ${gameFormData.title}` : 'Add New Game to Carousel'}</h2>

          <form onSubmit={handleSaveGame} className="admin-form">
            <div className="input-group">
              <label>Game Title</label>
              <input type="text" required value={gameFormData.title} onChange={(e) => setGameFormData({...gameFormData, title: e.target.value})} />
            </div>
            <div className="input-group">
              <label>Genre</label>
              <input type="text" required value={gameFormData.genre} onChange={(e) => setGameFormData({...gameFormData, genre: e.target.value})} />
            </div>
            <div className="input-group">
              <label>Image URL (Direct link to .jpg/.png)</label>
              <input type="text" required value={gameFormData.image_url} onChange={(e) => setGameFormData({...gameFormData, image_url: e.target.value})} />
            </div>

            {/* THE VISUAL CROPPING TOOL */}
            {gameFormData.image_url && (
                <div className="crop-area">
                    <label>Customize Frontpage Image framing</label>
                    <p className="crop-tip">The Red Box is what will be shown in the frontpage card.</p>
                    {/* The Library Component */}
                    <ReactCrop
                        crop={crop}
                        onChange={(c) => setCrop(c)}
                        onComplete={(c) => setCompletedCrop(c)}
                        aspect={ASPECT_RATIO} // Same aspect ratio as the frontpage card
                    >
                        <img src={gameFormData.image_url} alt="Image to crop" style={{ maxWidth: '100%', display: 'block' }} />
                    </ReactCrop>
                </div>
            )}

            <div className="form-actions">
              <button type="submit" className="add-btn">
                {isEditMode ? 'Save Changes' : '+ Upload to Grid'}
              </button>
              {isEditMode && (
                <button type="button" className="cancel-btn" onClick={resetFormState}>
                  Cancel Edit
                </button>
              )}
            </div>
          </form>
        </section>

        {/* MANAGE GAMES LIST (With new Edit button) */}
        <section className="admin-card list-section">
          <h2>Manage Current Games</h2>
          <div className="game-list">
            {games.map(game => (
              <div key={game.id} className="admin-game-row">
                <img src={game.image} alt="thumbnail" className="admin-thumb" loading="lazy" />
                <div className="admin-game-info">
                  <h4>{game.title}</h4>
                  <span>{game.genre}</span>
                </div>
                <div className="row-actions">
                    {/* The new EDIT button */}
                    <button className="edit-btn" onClick={() => handleEditClick(game)}>Edit</button>
                    <button className="delete-btn" onClick={() => handleDelete(game.id)}>Delete</button>
                </div>
              </div>
            ))}
          </div>
        </section>
      </div>
    </div>
  );
};

export default AdminDashboard;
